// Good
async function fetchUser(id: string): Promise<User> {
  const response = await fetch(`/api/users/${id}`);
  if (!response.ok) throw new HttpError(response.status);
  const data: unknown = await response.json();
  return validateUser(data); // validate/transform at boundary per TY405
}

// Bad - nested .then chains
function fetchUser(id: string): Promise<User> {
  return fetch(`/api/users/${id}`)
    .then((res) => {
      if (!res.ok) throw new HttpError(res.status);
      return res.json();
    })
    .then((data) => data as User);
}

// Good - concurrent independent fetches
const [user, orders] = await Promise.all([
  fetchUser(id),
  fetchOrders(id),
]);

// Good - partial failure OK
const results = await Promise.allSettled(urls.map(fetch));
const successes = results.filter(
  (r): r is PromiseFulfilledResult<Response> => r.status === "fulfilled"
);

// Bad - sequential when independent
const user = await fetchUser(id);
const orders = await fetchOrders(id);

// Good
async function fetchWithRetry(
  url: string,
  opts: { retries: number; signal?: AbortSignal },
): Promise<Response> {
  for (let i = 0; i <= opts.retries; i++) {
    opts.signal?.throwIfAborted();
    try {
      return await fetch(url, { signal: opts.signal });
    } catch (err) {
      if (i === opts.retries) throw err;
    }
  }
  throw new Error("unreachable");
}

// Good - typed event map
interface ServerEvents {
  connection: (socket: Socket) => void;
  error: (err: Error) => void;
  close: () => void;
}

interface TypedEmitter<T extends Record<string, (...args: unknown[]) => void>> {
  on<K extends keyof T>(event: K, listener: T[K]): void;
  emit<K extends keyof T>(event: K, ...args: Parameters<T[K]>): void;
}

const server: TypedEmitter<ServerEvents> = createServer();

// Good - async generator
async function* readLines(path: string): AsyncGenerator<string> {
  const stream = createReadStream(path);
  for await (const chunk of stream) {
    yield* chunk.toString().split("\n");
  }
}

// Good - consumption
for await (const line of readLines("data.csv")) {
  process(line);
}
